/* ========================= Geometry helpers ========================= */
const MARGIN = 16;
const LEFT_GUTTER = 260;
const DEFAULT_W = 1600;
const DEFAULT_H = 1100;
const MAX_UNDO = 60;

const deg = (r) => (r * 180) / Math.PI;
const rad = (d) => (d * Math.PI) / 180;

function rotatePoint([x, y], a) {
  const c = Math.cos(a), s = Math.sin(a);
  return [x * c - y * s, x * s + y * c];
}
function transformVerts(verts, pos, angle, mirrorX = 1) {
  const out = new Array(verts.length);
  for (let i = 0; i < verts.length; i++) {
    const [rx, ry] = rotatePoint([verts[i][0] * mirrorX, verts[i][1]], angle);
    out[i] = [rx + pos.x, ry + pos.y];
  }
  return out;
}
function pointInPoly(px, py, poly) {
  let inside = false;
  for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
    const [xi, yi] = poly[i], [xj, yj] = poly[j];
    const hit = yi > py !== yj > py && px < ((xj - xi) * (py - yi)) / (yj - yi + 1e-9) + xi;
    if (hit) inside = !inside;
  }
  return inside;
}
function centroid(poly) { let x=0,y=0; for (const p of poly){x+=p[0];y+=p[1];} return [x/poly.length,y/poly.length]; }
function dist(a,b){ return Math.hypot(a.x-b.x,a.y-b.y); }

/* ========================= Base pieces ========================= */
const UNIT = 100;
const tri = (leg) => { const h=leg/2; return [[-h,-h],[h,-h],[-h,h]]; };
const square = (side)=>{ const s=side/2; return [[-s,-s],[s,-s],[s,s],[-s,s]]; };
function para(side){
  // Right-leaning parallelogram (/) — matches standard tangram orientation.
  // At angle=0: top-right shifted right of bottom-left.
  // Splits cleanly into 2 small right-isosceles triangles along the vertical diagonal.
  const s = side/2, t = s;            // t = s gives 45° slant
  return [[0,-s],[s+t,-s],[0,s],[-(s+t),s]];
}

const COLORS = {
  L1: "#1E3FAE",  // Large  blue triangle   (matches your physical blue)
  L2: "#F5C800",  // Large  yellow triangle  (matches your physical yellow)
  M:  "#2A7A2A",  // Medium green triangle   (matches your physical green)
  S1: "#3A5FD9",  // Small  blue triangle    (lighter blue)
  S2: "#228B22",  // Small  green triangle   (matches your physical green)
  SQ: "#E8B800",  // Square yellow            (matches your physical yellow)
  P:  "#C41E1E",  // Parallelogram red        (matches your physical red)
};

function makePieces(boardH = DEFAULT_H) {
  const large=UNIT*2, medium=UNIT*Math.sqrt(2), small=UNIT, sq=UNIT, ps=UNIT;
  // Each piece gets its own (x, y) so none overlap at startup.
  // Two rows: large/medium on row1, small+square+para on row2.
  const row1y = Math.max(300, boardH - 320);
  const row2y = Math.max(460, boardH - 160);
  return [
    // ── Row 1: big pieces (spaced by 240px) ───────────────
    { id:"L1", verts:tri(large),  color:COLORS.L1, mirrorX:1, x:160,  y:row1y, angle:0       },
    { id:"L2", verts:tri(large),  color:COLORS.L2, mirrorX:1, x:420,  y:row1y, angle:0       },
    { id:"M",  verts:tri(medium), color:COLORS.M,  mirrorX:1, x:650,  y:row1y, angle:0       },
    // ── Row 2: small pieces (spaced by 180px) ─────────────
    { id:"S1", verts:tri(small),  color:COLORS.S1, mirrorX:1, x:150,  y:row2y, angle:0       },
    { id:"S2", verts:tri(small),  color:COLORS.S2, mirrorX:1, x:330,  y:row2y, angle:0       },
    { id:"SQ", verts:square(sq),  color:COLORS.SQ, mirrorX:1, x:500,  y:row2y, angle:0       },
    // P at angle=0: 200px wide × 100px tall — clearly visible and easy to grab
    { id:"P",  verts:para(ps),    color:COLORS.P,  mirrorX:1, x:690,  y:row2y, angle:0       },
  ];
}

