// Build the 113 Magnetico puzzle entries using real silhouette images from the book.
// Each entry has a hintImage (the blue silhouette) so players can trace the shape.
function buildEbook113(){
  const entries=[], rots=[0,45,90,135,180,225,270,315], mirs=[1,-1];
  const offsets=[[0,0],[10,0],[-10,0],[0,10],[0,-10],[20,0],[0,20],[-20,0],[0,-20]];
  const C={x:455,y:305};
  const hintMap = Object.fromEntries(MAGNETICO_DATA);
  outer: for(const seedName of Object.keys(SEEDS)){
    for(const r of rots){ const A=rad(r);
      for(const m of mirs){
        for(const [dx,dy] of offsets){
          const src=SEEDS[seedName]; const solution={};
          for(const id of Object.keys(src)){
            const t=src[id]; const [rx,ry]=rotatePoint([t.x-C.x,t.y-C.y],A);
            solution[id]={x:C.x+rx+dx, y:C.y+ry+dy, angle:rad(t.a+r), mirrorX:(t.m||1)*m};
          }
          const n = entries.length + 1;
          const dataUrl = hintMap[n];
          const entry = { name:`E-Book ${n}`, solution };
          if (dataUrl) {
            entry.hintImage = { dataUrl, x:455, y:305, scale:0.55, angle:0, opacity:0.45 };
          }
          entries.push(entry);
          if(entries.length>=113) break outer;
        }
      }
    }
  }
  return entries;
}
const EBOOK_113 = buildEbook113();

