/* ========================= Sound Engine ========================= */
const SoundEngine = {
  ctx: null,
  enabled: true,
  getCtx() {
    if (!this.ctx) {
      try { this.ctx = new (window.AudioContext || window.webkitAudioContext)(); } catch(e){}
    }
    return this.ctx;
  },
  play(type) {
    if (!this.enabled) return;
    const ctx = this.getCtx();
    if (!ctx) return;
    if (ctx.state === 'suspended') ctx.resume();
    const now = ctx.currentTime;
    const g = ctx.createGain();
    g.connect(ctx.destination);
    const o = ctx.createOscillator();
    o.connect(g);

    switch(type) {
      case 'pickup':
        o.type = 'sine';
        o.frequency.setValueAtTime(440, now);
        o.frequency.exponentialRampToValueAtTime(660, now + 0.08);
        g.gain.setValueAtTime(0.15, now);
        g.gain.exponentialRampToValueAtTime(0.001, now + 0.12);
        o.start(now); o.stop(now + 0.12);
        break;
      case 'place':
        o.type = 'sine';
        o.frequency.setValueAtTime(330, now);
        o.frequency.exponentialRampToValueAtTime(220, now + 0.1);
        g.gain.setValueAtTime(0.12, now);
        g.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
        o.start(now); o.stop(now + 0.15);
        break;
      case 'rotate':
        o.type = 'triangle';
        o.frequency.setValueAtTime(600, now);
        o.frequency.exponentialRampToValueAtTime(800, now + 0.04);
        g.gain.setValueAtTime(0.06, now);
        g.gain.exponentialRampToValueAtTime(0.001, now + 0.06);
        o.start(now); o.stop(now + 0.06);
        break;
      case 'snap':
        // Pleasant chime for snap-to-solution
        [0, 0.05, 0.1].forEach((offset, i) => {
          const o2 = ctx.createOscillator();
          const g2 = ctx.createGain();
          o2.connect(g2); g2.connect(ctx.destination);
          o2.type = 'sine';
          const freqs = [523, 659, 784];
          o2.frequency.setValueAtTime(freqs[i], now + offset);
          g2.gain.setValueAtTime(0.12, now + offset);
          g2.gain.exponentialRampToValueAtTime(0.001, now + offset + 0.3);
          o2.start(now + offset); o2.stop(now + offset + 0.3);
        });
        return;
      case 'success':
        [0, 0.1, 0.2, 0.32].forEach((offset, i) => {
          const o2 = ctx.createOscillator();
          const g2 = ctx.createGain();
          o2.connect(g2); g2.connect(ctx.destination);
          o2.type = 'sine';
          const freqs = [523, 659, 784, 1047];
          o2.frequency.setValueAtTime(freqs[i], now + offset);
          g2.gain.setValueAtTime(0.18, now + offset);
          g2.gain.exponentialRampToValueAtTime(0.001, now + offset + 0.4);
          o2.start(now + offset); o2.stop(now + offset + 0.4);
        });
        return;
      case 'undo':
        o.type = 'sawtooth';
        o.frequency.setValueAtTime(400, now);
        o.frequency.exponentialRampToValueAtTime(200, now + 0.1);
        g.gain.setValueAtTime(0.08, now);
        g.gain.exponentialRampToValueAtTime(0.001, now + 0.12);
        o.start(now); o.stop(now + 0.12);
        break;
      default: break;
    }
  }
};

