/* ========================= Book Importer ========================= */
function BookImporter({ onCreateMany }) {
  const canvasRef = React.useRef(null);
  const [mode, setMode] = React.useState("none");
  const [pdf, setPdf] = React.useState(null);
  const [numPages, setNumPages] = React.useState(0);
  const [pageIndex, setPageIndex] = React.useState(1);
  const [scale, setScale] = React.useState(1.2);
  const [imgURL, setImgURL] = React.useState("");
  const [boxes, setBoxes] = React.useState([]);
  const [drag, setDrag] = React.useState(null);
  const [selectedIdx, setSelectedIdx] = React.useState(-1);
  const [trimOn, setTrimOn] = React.useState(true);
  const [trimThresh, setTrimThresh] = React.useState(210);
  const [pdfSize, setPdfSize] = React.useState({ w: 900, h: 1200 });
  const pdfjsRef = React.useRef(null);

  async function ensurePdfjs(){
    if (pdfjsRef.current) return pdfjsRef.current;
    // Try modern pdfjs-dist (v3/v4) first, then fall back to legacy (v2).
    // @vite-ignore tells Vite not to try resolving this at build time.
    try {
      const lib = await import(/* @vite-ignore */ "pdfjs-dist/build/pdf.mjs");
      // Worker: resolve against the installed package so no CDN needed
      const workerSrc = new URL(
        "pdfjs-dist/build/pdf.worker.mjs",
        import.meta.url
      ).href;
      lib.GlobalWorkerOptions.workerSrc = workerSrc;
      pdfjsRef.current = lib;
      return lib;
    } catch (_e1) {
      // Legacy build (pdfjs-dist v2.x) with CDN worker
      try {
        const lib = await import(/* @vite-ignore */ "pdfjs-dist/legacy/build/pdf");
        lib.GlobalWorkerOptions.workerSrc =
          "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
        pdfjsRef.current = lib;
        return lib;
      } catch (_e2) {
        throw new Error("pdfjs-dist could not be loaded. Run: npm i pdfjs-dist  then restart the dev server.");
      }
    }
  }

  const loadPdf = async (file) => {
    try {
      const lib = await ensurePdfjs();
      const buf = await file.arrayBuffer();
      const doc = await lib.getDocument({ data: buf }).promise;
      // Set state — the useEffect watching [mode,pdf,pageIndex,scale] will
      // call renderPdfPage once React re-renders and canvas is mounted.
      setPdf(doc);
      setNumPages(doc.numPages);
      setPageIndex(1);
      setBoxes([]);
      setSelectedIdx(-1);
      setMode("pdf");
      // Also render immediately using offscreen canvas (safe — no ref needed)
      await renderPdfPage(doc, 1, scale);
    } catch(err) {
      console.error("PDF load error:", err);
      alert("Could not load PDF.\n\nError: " + err.message);
    }
  };

  const renderPdfPage = async (doc, idx, sc) => {
    const page = await doc.getPage(idx);
    const viewport = page.getViewport({ scale: sc });
    // Always use an offscreen canvas — never touch canvasRef directly here.
    // This avoids the "canvasRef.current is null" error when React hasn't mounted yet.
    const offscreen = document.createElement("canvas");
    offscreen.width = viewport.width;
    offscreen.height = viewport.height;
    const ctx = offscreen.getContext("2d");
    await page.render({ canvasContext: ctx, viewport }).promise;
    // Store dimensions so useEffect can resize canvasRef correctly
    setPdfSize({ w: viewport.width, h: viewport.height });
    setImgURL(offscreen.toDataURL("image/png"));
  };

  useEffect(()=>{ if(mode==="pdf"&&pdf) renderPdfPage(pdf,pageIndex,scale); },[mode,pdf,pageIndex,scale]);

  const loadImage = (file) => {
    const reader = new FileReader();
    reader.onload = () => {
      setMode("image"); setImgURL(reader.result);
      const img = new Image();
      img.onload = () => {
        const c = canvasRef.current;
        c.width = img.width; c.height = img.height;
        c.getContext("2d").drawImage(img, 0, 0);
      };
      img.src = reader.result;
      setBoxes([]); setSelectedIdx(-1);
    };
    reader.readAsDataURL(file);
  };

  useEffect(() => {
    if (!imgURL) return;
    const img = new Image();
    img.onload = () => {
      const c = canvasRef.current;
      if (!c) return; // canvas not yet mounted — React will re-run when it mounts
      if (mode === "image") {
        c.width = img.width;
        c.height = img.height;
      } else if (mode === "pdf") {
        c.width = pdfSize.w;
        c.height = pdfSize.h;
      }
      const ctx = c.getContext("2d");
      ctx.clearRect(0, 0, c.width, c.height);
      ctx.drawImage(img, 0, 0, c.width, c.height);
    };
    img.src = imgURL;
  }, [imgURL, mode, pdfSize]);

  function localXY(e){ const r=e.currentTarget.getBoundingClientRect(); return {x:e.clientX-r.left,y:e.clientY-r.top}; }
  function onDown(e){
    if(!imgURL) return;
    const {x,y}=localXY(e);
    for(let i=boxes.length-1;i>=0;i--){
      const b=boxes[i];
      if(x>=b.x-6&&x<=b.x+b.w+6&&y>=b.y-6&&y<=b.y+b.h+6){
        setSelectedIdx(i);
        setDrag({mode:"move",x0:x,y0:y,b:{...b}});
        return;
      }
    }
    setSelectedIdx(-1);
    setDrag({mode:"draw",sx:x,sy:y,x,y});
  }
  function onMove(e){
    if(!drag) return;
    const {x,y}=localXY(e);
    if(drag.mode==="draw"){setDrag({...drag,x,y});return;}
    if(drag.mode==="move"&&selectedIdx>=0){
      const dx=x-drag.x0,dy=y-drag.y0;
      setBoxes(bs=>bs.map((b,i)=>i===selectedIdx?{...b,x:drag.b.x+dx,y:drag.b.y+dy}:b));
    }
  }
  function onUp(){
    if(!drag) return;
    if(drag.mode==="draw"){
      const x=Math.min(drag.sx,drag.x),y=Math.min(drag.sy,drag.y);
      const w=Math.abs(drag.x-drag.sx),h=Math.abs(drag.y-drag.sy);
      if(w>12&&h>12){ setBoxes(b=>[...b,{x,y,w,h,name:`Form #${b.length+1}`}]); setSelectedIdx(boxes.length); }
    }
    setDrag(null);
  }

  useEffect(()=>{
    const onKey=(e)=>{
      if((e.key==="Delete"||e.key==="Backspace")&&selectedIdx>=0){
        setBoxes(b=>b.filter((_,i)=>i!==selectedIdx)); setSelectedIdx(-1);
      }
    };
    window.addEventListener("keydown",onKey);
    return ()=>window.removeEventListener("keydown",onKey);
  },[selectedIdx]);

  function cropRectFromCanvas(rect){
    const src=canvasRef.current;
    const c=document.createElement("canvas"); c.width=rect.w; c.height=rect.h;
    const ctx=c.getContext("2d");
    ctx.drawImage(src,rect.x,rect.y,rect.w,rect.h,0,0,rect.w,rect.h);
    if(!trimOn) return c.toDataURL("image/png");
    const imgData=ctx.getImageData(0,0,rect.w,rect.h);
    const{data,width,height}=imgData;
    let minX=width,minY=height,maxX=-1,maxY=-1;
    for(let y=0;y<height;y++) for(let x=0;x<width;x++){
      const i=(y*width+x)*4;
      const r=data[i],g=data[i+1],b=data[i+2],a=data[i+3];
      if(a>10&&(r<trimThresh||g<trimThresh||b<trimThresh)){
        if(x<minX)minX=x; if(x>maxX)maxX=x;
        if(y<minY)minY=y; if(y>maxY)maxY=y;
      }
    }
    if(maxX>=minX&&maxY>=minY){
      const w=maxX-minX+1,h=maxY-minY+1;
      const out=document.createElement("canvas"); out.width=w; out.height=h;
      out.getContext("2d").drawImage(c,minX,minY,w,h,0,0,w,h);
      return out.toDataURL("image/png");
    }
    return c.toDataURL("image/png");
  }

  const sel=boxes[selectedIdx];
  return (
    <div style={{
      border:"1px solid #E5E7EB", borderRadius:12, background:"#FAFAFA",
      margin:`8px 12px 8px ${12+LEFT_GUTTER}px`
    }}>
      <details>
        <summary style={{cursor:"pointer",padding:"10px 14px",fontWeight:700,color:"#374151",fontSize:14}}>
          📂 Book / Image Importer
        </summary>
        <div style={{display:"flex",gap:10,alignItems:"center",padding:"8px 14px",flexWrap:"wrap",borderTop:"1px solid #F3F4F6"}}>
          <FileBtn label="📄 Load PDF" accept="application/pdf" onChange={e=>e.target.files?.[0]&&loadPdf(e.target.files[0])}/>
          <FileBtn label="🖼️ Load Image" accept="image/*" onChange={e=>e.target.files?.[0]&&loadImage(e.target.files[0])}/>
          {mode==="pdf"&&<>
            <label style={labelStyle}>Page <input type="number" min="1" max={numPages||1} value={pageIndex}
              onChange={e=>setPageIndex(Math.min(Math.max(1,+e.target.value),numPages||1))} style={{width:56,marginLeft:4}}/> / {numPages||1}</label>
            <label style={labelStyle}>Zoom <input type="range" min="0.6" max="2" step="0.05" value={scale}
              onChange={e=>setScale(+e.target.value)} style={{marginLeft:4}}/></label>
          </>}
          <label style={labelStyle}><input type="checkbox" checked={trimOn} onChange={e=>setTrimOn(e.target.checked)}/> Auto-trim</label>
          <label style={labelStyle}>Threshold <input type="range" min="0" max="255" value={trimThresh}
            onChange={e=>setTrimThresh(+e.target.value)} style={{marginLeft:4}}/></label>
          <Btn onClick={()=>{setBoxes([]);setSelectedIdx(-1);}}>Clear Boxes</Btn>
          <Btn onClick={()=>{
            if(selectedIdx<0||!imgURL)return;
            const b=boxes[selectedIdx];
            onCreateMany([{name:b.name?.trim()||`Form ${selectedIdx+1}`,hintImage:{dataUrl:cropRectFromCanvas(b),x:455,y:305,scale:1,angle:0,opacity:0.23}}]);
          }} disabled={selectedIdx<0}>Add Selected</Btn>
          <Btn primary onClick={()=>{
            if(!boxes.length||!imgURL)return;
            onCreateMany(boxes.map((b,i)=>({name:b.name?.trim()||`Form ${i+1}`,hintImage:{dataUrl:cropRectFromCanvas(b),x:455,y:305,scale:1,angle:0,opacity:0.23}})));
          }} disabled={!boxes.length}>Add All ({boxes.length})</Btn>
        </div>
        {sel&&<div style={{display:"flex",gap:10,alignItems:"center",padding:"4px 14px 8px",flexWrap:"wrap"}}>
          <label style={labelStyle}>Name <input value={sel.name||""} onChange={e=>setBoxes(bs=>bs.map((b,i)=>i===selectedIdx?{...b,name:e.target.value}:b))} style={{width:240,marginLeft:4}}/></label>
          <Btn onClick={()=>{setBoxes(b=>b.filter((_,i)=>i!==selectedIdx));setSelectedIdx(-1);}}>🗑 Delete</Btn>
        </div>}
        {imgURL&&<div style={{padding:10,overflow:"auto"}}>
          <div style={{position:"relative",display:"inline-block"}} onMouseDown={onDown} onMouseMove={onMove} onMouseUp={onUp}>
            <canvas ref={canvasRef} style={{display:"block",border:"1px solid #E5E7EB",borderRadius:8}}/>
            {boxes.map((b,i)=>(
              <div key={i} onMouseDown={e=>{e.stopPropagation();setSelectedIdx(i);}} style={{
                position:"absolute",left:b.x,top:b.y,width:b.w,height:b.h,
                border:i===selectedIdx?"2px solid #6366F1":"2px dashed #6366F1",
                background:"rgba(99,102,241,0.08)",boxSizing:"border-box"
              }}/>
            ))}
            {drag?.mode==="draw"&&<div style={{
              position:"absolute",
              left:Math.min(drag.sx,drag.x),top:Math.min(drag.sy,drag.y),
              width:Math.abs(drag.x-drag.sx),height:Math.abs(drag.y-drag.sy),
              border:"2px solid #6366F1",background:"rgba(99,102,241,0.15)",boxSizing:"border-box"
            }}/>}
          </div>
        </div>}
      </details>
    </div>
  );
}
function FileBtn({label,accept,onChange}){
  return <label style={{...btnBaseStyle,cursor:"pointer",userSelect:"none"}}>{label}<input type="file" accept={accept} style={{display:"none"}} onChange={onChange}/></label>;
}
const labelStyle={fontSize:13,display:"flex",alignItems:"center",gap:2,color:"#374151"};

/* ========================= Progress Bar ========================= */
function ProgressBar({ snappedCount, total }) {
  const pct = total > 0 ? (snappedCount / total) * 100 : 0;
  return (
    <div style={{display:"flex",alignItems:"center",gap:8}}>
      <span style={{fontSize:12,color:"#6B7280",whiteSpace:"nowrap"}}>{snappedCount}/{total} placed</span>
      <div style={{
        width:100, height:8, background:"#E5E7EB", borderRadius:999, overflow:"hidden"
      }}>
        <div style={{
          height:"100%", width:`${pct}%`,
          background: pct===100 ? "linear-gradient(90deg,#34D399,#10B981)" : "linear-gradient(90deg,#818CF8,#6366F1)",
          borderRadius:999,
          transition:"width 0.4s cubic-bezier(.22,1,.36,1)"
        }}/>
      </div>
    </div>
  );
}

/* ========================= Main ========================= */
export default function TangramTilesGame_2({ onQuit }) {
  const svgRef = useRef(null);

  const [boardW, setBoardW] = useState(DEFAULT_W);
  const [boardH, setBoardH] = useState(DEFAULT_H);
  const [pieces, setPieces] = useState(makePieces(DEFAULT_H));
  const [selected, setSelected] = useState(null);
  const [moves, setMoves] = useState(0);
  const [elapsed, setElapsed] = useState(0);
  const [timerOn, setTimerOn] = useState(false);
  const [msg, setMsg] = useState("");
  const [msgType, setMsgType] = useState("info"); // "info"|"success"|"error"
  const [showHint, setShowHint] = useState(true);
  const [snap, setSnap] = useState({ grid:15, angle:45 });
  const [puzzleName, setPuzzleName] = useState("Freestyle");
  const [customList, setCustomList] = useState(loadCustomList());
  const [rulesOpen, setRulesOpen] = useState(false);
  const [soundOn, setSoundOn] = useState(true);
  const [snappedPieces, setSnappedPieces] = useState(new Set());

  // Trace Mode
  const [traceOn, setTraceOn] = useState(false);
  const [trace, setTrace] = useState({ url:"", x:DEFAULT_W/2, y:DEFAULT_H/2, scale:0.9, angle:0, opacity:0.25 });

  // Undo/Redo
  const [history, setHistory] = useState([]);
  const [future, setFuture] = useState([]);
  const historyRef = useRef(history);
  const futureRef = useRef(future);
  useEffect(()=>{ historyRef.current=history; },[history]);
  useEffect(()=>{ futureRef.current=future; },[future]);

  // Live refs
  const piecesRef = useRef(pieces); useEffect(()=>{ piecesRef.current=pieces; },[pieces]);
  const selectedRef = useRef(selected); useEffect(()=>{ selectedRef.current=selected; },[selected]);
  const snapRef = useRef(snap); useEffect(()=>{ snapRef.current=snap; },[snap]);
  const soundRef = useRef(soundOn); useEffect(()=>{ soundRef.current=soundOn; SoundEngine.enabled=soundOn; },[soundOn]);
  const snappedRef = useRef(snappedPieces); useEffect(()=>{ snappedRef.current=snappedPieces; },[snappedPieces]);

  // Push to undo history
  const pushHistory = useCallback((state) => {
    setHistory(h => {
      const next = [...h, state].slice(-MAX_UNDO);
      return next;
    });
    setFuture([]);
  }, []);

  // Timer
  useEffect(()=>{
    let id=null;
    if(timerOn) id=setInterval(()=>setElapsed(t=>t+1),1000);
    return ()=>id&&clearInterval(id);
  },[timerOn]);

  // Undo/Redo keyboard
  useEffect(()=>{
    const onKey = (e) => {
      // Ignore when typing in an input
      if (e.target.tagName==="INPUT"||e.target.tagName==="SELECT"||e.target.tagName==="TEXTAREA") return;

      if ((e.ctrlKey||e.metaKey) && e.key==='z' && !e.shiftKey) {
        e.preventDefault();
        const h = historyRef.current;
        if (!h.length) return;
        const prev = h[h.length-1];
        setFuture(f => [piecesRef.current, ...f]);
        setHistory(h2 => h2.slice(0,-1));
        setPieces(prev);
        SoundEngine.play('undo');
      }
      if ((e.ctrlKey||e.metaKey) && (e.key==='y'||(e.key==='z'&&e.shiftKey))) {
        e.preventDefault();
        const f = futureRef.current;
        if (!f.length) return;
        const next = f[0];
        setHistory(h => [...h, piecesRef.current].slice(-MAX_UNDO));
        setFuture(f2 => f2.slice(1));
        setPieces(next);
        SoundEngine.play('pickup');
      }
      // R = rotate selected piece +45°, Shift+R = −45°
      if (e.key==='r'||e.key==='R') {
        e.preventDefault();
        const id = selectedRef.current;
        if (!id) return;
        pushHistory([...piecesRef.current]);
        const step = e.shiftKey ? -rad(45) : rad(45);
        setPieces(arr=>arr.map(p=>{
          if(p.id!==id) return p;
          const raw = p.angle + step;
          return {...p, angle:((raw%(Math.PI*2))+(Math.PI*2))%(Math.PI*2)};
        }));
        SoundEngine.play('rotate');
      }
      // F = flip parallelogram
      if (e.key==='f'||e.key==='F') {
        e.preventDefault();
        pushHistory([...piecesRef.current]);
        setPieces(arr=>arr.map(p=>p.id==="P"?{...p,mirrorX:p.mirrorX*-1}:p));
        setSelected("P");
        SoundEngine.play('rotate');
      }
    };
    window.addEventListener('keydown', onKey);
    return ()=>window.removeEventListener('keydown', onKey);
  }, []);

  // Wheel rotate
  useEffect(()=>{
    const svg = svgRef.current;
    if (!svg) return;
    const onWheel = (e) => {
      e.preventDefault(); e.stopPropagation();
      const r = svg.getBoundingClientRect();
      const id = hitAt(piecesRef.current, e.clientX-r.left, e.clientY-r.top);
      if (!id) return;
      setSelected(id);
      pushHistory([...piecesRef.current]);
      // Always snap to 45° per scroll tick — clean angles every time
      // Shift held = finer 15° steps for advanced users
      const step = e.shiftKey ? rad(15) : rad(45);
      const dir  = e.deltaY > 0 ? 1 : -1;
      setPieces(arr=>arr.map(p=>{
        if(p.id!==id) return p;
        const raw = p.angle + dir*step;
        // Normalise to [0, 2π)
        const norm = ((raw % (Math.PI*2)) + Math.PI*2) % (Math.PI*2);
        return {...p, angle: norm};
      }));
      SoundEngine.play('rotate');
    };
    svg.addEventListener("wheel", onWheel, {passive:false});
    return ()=>svg.removeEventListener("wheel", onWheel);
  }, [pushHistory]);

  // Drag
  const dragHandlers = useRef(null);
  useEffect(()=>{
    let dragging=false, dragId=null, ox=0, oy=0;
    const onDown = (id, e) => {
      e.preventDefault();
      pushHistory([...piecesRef.current]);
      setSelected(id);
      setPieces(arr=>{ const idx=arr.findIndex(p=>p.id===id); const mv=arr[idx], rest=arr.filter((_,i)=>i!==idx); return [...rest,mv]; });
      const r = svgRef.current.getBoundingClientRect();
      const p = piecesRef.current.find(pp=>pp.id===id);
      ox = (e.clientX-r.left)-p.x; oy = (e.clientY-r.top)-p.y;
      dragging=true; dragId=id;
      if(!timerOn) setTimerOn(true);
      SoundEngine.play('pickup');
    };
    const onMove = (e) => {
      if(!dragging) return;
      const r = svgRef.current.getBoundingClientRect();
      const nx = Math.max(MARGIN,Math.min(boardW-MARGIN,(e.clientX-r.left)-ox));
      const ny = Math.max(MARGIN,Math.min(boardH-MARGIN,(e.clientY-r.top)-oy));
      setPieces(arr=>arr.map(p=>p.id===dragId?{...p,x:nx,y:ny}:p));
    };
    const onUp = () => {
      if(!dragging) return;
      dragging=false; dragId=null; setMoves(m=>m+1);
      const g=snapRef.current.grid, id=selectedRef.current;
      if(g>0&&id) setPieces(arr=>arr.map(p=>p.id===id?{...p,x:Math.round(p.x/g)*g,y:Math.round(p.y/g)*g}:p));
      SoundEngine.play('place');
      // Check snap after placement
      setTimeout(()=>checkSnapHighlight(), 50);
    };
    window.addEventListener("pointermove", onMove);
    window.addEventListener("pointerup", onUp);
    dragHandlers.current = onDown;
    return ()=>{ window.removeEventListener("pointermove",onMove); window.removeEventListener("pointerup",onUp); };
  }, [timerOn, boardW, boardH, pushHistory]);

  // Snap highlight check
  function checkSnapHighlight() {
    const entry = currentEntryRef.current;
    if (!entry?.solution) return;
    const sol = entry.solution;
    const tolPos=28, tolAng=rad(14);
    const newSnapped = new Set();
    let allSnapped = true;
    for (const id of Object.keys(sol)) {
      const p = piecesRef.current.find(x=>x.id===id);
      const t = sol[id];
      const da = Math.abs(((p.angle-(t.angle||0)+Math.PI)%(2*Math.PI))-Math.PI);
      const close = dist(p,t)<tolPos && da<tolAng && (t.mirrorX||1)===(p.mirrorX||1);
      if (close) newSnapped.add(id);
      else allSnapped = false;
    }
    const prev = snappedRef.current;
    // Play snap sound for newly snapped pieces
    const newlySnapped = [...newSnapped].filter(id=>!prev.has(id));
    if (newlySnapped.length > 0) SoundEngine.play('snap');
    setSnappedPieces(newSnapped);
    if (allSnapped && Object.keys(sol).length > 0) {
      flash("🎉 Perfect fit!", "success");
      SoundEngine.play('success');
    }
  }

  const currentEntryRef = useRef(null);

  function currentEntry(){
    if(puzzleName==="Freestyle") return null;
    // Any named built-in shape
    if(NAMED_SHAPES[puzzleName]){
      const src=NAMED_SHAPES[puzzleName]; const sol={};
      for(const id of Object.keys(src)){ const t=src[id]; sol[id]={x:t.x,y:t.y,angle:rad(t.a),mirrorX:t.m||1}; }
      return {solution:sol};
    }
    if(/^E-Book \d+$/.test(puzzleName)){ const idx=parseInt(puzzleName.replace("E-Book ",""))-1; return EBOOK_113[idx]; }
    return customList.find(x=>x.name===puzzleName)||null;
  }
  const entry = currentEntry();
  currentEntryRef.current = entry;

  const snappedCount = entry?.solution ? [...Object.keys(entry.solution)].filter(id=>snappedPieces.has(id)).length : 0;
  const totalPieces = entry?.solution ? Object.keys(entry.solution).length : 0;

  function hitAt(arr,x,y){ for(let i=arr.length-1;i>=0;i--){ const p=arr[i]; const poly=transformVerts(p.verts,{x:p.x,y:p.y},p.angle,p.mirrorX); if(pointInPoly(x,y,poly)) return p.id; } return null; }
  function snapAngle(a,snapDeg){ if(!snapDeg||snapDeg<=0)return a; return rad(Math.round((deg(a)%360)/snapDeg)*snapDeg); }
  function flash(t, type="info"){
    setMsg(t); setMsgType(type);
    setTimeout(()=>setMsg(""),type==="success"?2500:1500);
  }

  function checkFit(){
    const e=currentEntry();
    if(!e||!e.solution) return flash("No solution stored. Solve & click 'Use Current Layout as Solution'.","error");
    const sol=e.solution, tolPos=18, tolAng=rad(10);
    let ok=true;
    for(const id of Object.keys(sol)){
      const p=piecesRef.current.find(x=>x.id===id), t=sol[id];
      const da=Math.abs(((p.angle-(t.angle||0)+Math.PI)%(2*Math.PI))-Math.PI);
      if(!(dist(p,t)<tolPos&&da<tolAng&&(t.mirrorX||1)===(p.mirrorX||1))){ ok=false; break; }
    }
    if(ok){ flash("🎉 Perfect fit!","success"); SoundEngine.play('success'); }
    else flash("Not quite — nudge & rotate.","error");
  }

  function startPuzzle(name){
    setPuzzleName(name); setShowHint(true);
    setPieces(makePieces(boardH)); setSelected(null);
    setMoves(0); setElapsed(0); setTimerOn(false);
    setHistory([]); setFuture([]); setSnappedPieces(new Set());
  }

  function exportPNG(){
    const svg=svgRef.current, xml=new XMLSerializer().serializeToString(svg);
    const blob=new Blob([xml],{type:"image/svg+xml;charset=utf-8"}); const url=URL.createObjectURL(blob);
    const img=new Image(); img.onload=()=>{
      const c=document.createElement("canvas"); c.width=boardW; c.height=boardH;
      const ctx=c.getContext("2d"); ctx.fillStyle="#fff"; ctx.fillRect(0,0,c.width,c.height); ctx.drawImage(img,0,0);
      const a=document.createElement("a"); a.href=c.toDataURL("image/png"); a.download="tangram.png"; a.click(); URL.revokeObjectURL(url);
    };
    img.src=url;
  }

  function doSave(){ localStorage.setItem("TANGRAM_SVG_SAVE",JSON.stringify({pieces,moves,elapsed,snap,puzzleName,boardW,boardH})); flash("Saved ✓"); }
  function doLoad(){
    const raw=localStorage.getItem("TANGRAM_SVG_SAVE"); if(!raw) return flash("No save found.","error");
    try{
      const d=JSON.parse(raw);
      setPieces(d.pieces||makePieces(boardH)); setMoves(d.moves||0); setElapsed(d.elapsed||0);
      setSnap(d.snap||{grid:15,angle:1}); setPuzzleName(d.puzzleName||"Freestyle");
      if(d.boardW) setBoardW(d.boardW); if(d.boardH) setBoardH(d.boardH);
      setHistory([]); setFuture([]);
      flash("Loaded ✓");
    }catch{ flash("Failed to load.","error"); }
  }

  function onTraceFile(e){
    const f=e.target.files?.[0]; if(!f) return;
    const reader=new FileReader();
    reader.onload=()=>{ setTrace(t=>({...t,url:reader.result})); setTraceOn(true); flash("Image loaded. Align, then save."); };
    reader.readAsDataURL(f);
  }
  function saveImageAsPuzzle(){
    if(!trace.url) return flash("Load an image first.","error");
    const name=prompt("Name this photo puzzle:"); if(!name) return;
    const entry={name,hintImage:{dataUrl:trace.url,x:trace.x,y:trace.y,scale:trace.scale,angle:trace.angle,opacity:trace.opacity}};
    const list=[...customList.filter(c=>c.name!==name),entry];
    setCustomList(list); saveCustomList(list); setPuzzleName(name); setShowHint(true);
    flash(`Saved as "${name}"`);
  }
  function useCurrentLayoutAsSolution(){
    const idx=customList.findIndex(c=>c.name===puzzleName);
    if(idx<0) return flash("Select a Custom puzzle first.","error");
    const solution={}; for(const p of piecesRef.current){ solution[p.id]={x:p.x,y:p.y,angle:p.angle,mirrorX:p.mirrorX||1}; }
    const list=customList.slice(); list[idx]={...list[idx],solution};
    setCustomList(list); saveCustomList(list);
    flash("Solution saved ✓","success");
  }
  function deleteCurrentCustom(){
    if(!/^E-Book/.test(puzzleName)&&puzzleName!=="Freestyle"&&!NAMED_SHAPES[puzzleName]){
      const list=customList.filter(c=>c.name!==puzzleName); setCustomList(list); saveCustomList(list);
      setPuzzleName("Freestyle"); flash("Deleted.");
    } else flash("Pick a Custom puzzle to delete.","error");
  }

  const puzzleOptions = [
    {label:"Freestyle",value:"Freestyle"},
    {label:"— Built-in Shapes —",value:"_sep0",disabled:true},
    ...Object.keys(NAMED_SHAPES).map(n=>({label:n,value:n})),
    {label:"— E-Book (auto) —",value:"_sep1",disabled:true},
    ...EBOOK_113.map((_,i)=>({label:`E-Book ${i+1}`,value:`E-Book ${i+1}`})),
    {label:"— Custom (Saved) —",value:"_sep2",disabled:true},
    ...customList.map(c=>({label:c.name,value:c.name}))
  ];

  const pts = (poly) => poly.map(([x,y])=>`${x},${y}`).join(" ");
  const fmtTime = `${Math.floor(elapsed/60)}:${String(elapsed%60).padStart(2,"0")}`;

  return (
    <div style={{
      background:"#F8FAFC", color:"#111827",
      fontFamily:'"DM Sans",system-ui,-apple-system,sans-serif',
      height:"100vh", display:"flex", flexDirection:"column",
      overflow:"hidden"
    }}>
      {/* ── TOP BAR ── */}
      <div style={{
        display:"flex", alignItems:"center", gap:8, flexWrap:"wrap",
        padding:"10px 16px", paddingLeft:LEFT_GUTTER+12,
        borderBottom:"1px solid #E5E7EB",
        background:"#fff",
        boxShadow:"0 1px 4px rgba(0,0,0,0.05)"
      }}>
        {/* Logo */}
        <div style={{
          fontFamily:"'Georgia',serif", fontWeight:700, fontSize:18,
          color:"#4F46E5", letterSpacing:-0.5, marginRight:8, whiteSpace:"nowrap"
        }}>🧩 Tangram</div>

        {/* Form select */}
        <label style={{fontSize:13,color:"#6B7280",display:"flex",alignItems:"center",gap:4}}>
          Form
          <select value={puzzleName} onChange={e=>startPuzzle(e.target.value)} style={{
            marginLeft:4, padding:"5px 8px", borderRadius:8, border:"1px solid #D1D5DB",
            background:"#F9FAFB", fontSize:13, cursor:"pointer"
          }}>
            {puzzleOptions.map(o=><option key={o.value} value={o.value} disabled={o.disabled}>{o.label}</option>)}
          </select>
        </label>

        <div style={{width:1,height:24,background:"#E5E7EB"}}/>

        <Btn onClick={()=>setShowHint(v=>!v)} active={showHint}>{showHint?"👁 Hide Hint":"👁 Show Hint"}</Btn>
        <Btn onClick={()=>setRulesOpen(true)}>📖 Rules</Btn>
        <Btn onClick={checkFit} primary>✓ Check Fit</Btn>
        <Btn onClick={()=>{
          // Auto-select P if not already selected, then flip
          pushHistory([...pieces]);
          setPieces(arr=>arr.map(p=>p.id==="P"?{...p,mirrorX:p.mirrorX*-1}:p));
          setSelected("P");
          SoundEngine.play('rotate');
          flash("▱ Parallelogram flipped", "info");
        }}>↔ Flip ▱</Btn>
        <Btn onClick={()=>{
          pushHistory([...pieces]);
          setPieces(arr=>arr.map(p=>({
            ...p,
            x: MARGIN + 120 + Math.random()*(boardW - 280),
            y: MARGIN + 80  + Math.random()*(boardH - 200),
            // P stays flat (angle=0 or 180) so it's always wide and clickable
            angle: p.id==="P"
              ? rad(Math.floor(Math.random()*2)*180)
              : rad(Math.floor(Math.random()*8)*45),
          })));
          setSnappedPieces(new Set());
          SoundEngine.play('pickup');
        }}>🔀 Shuffle</Btn>

        <div style={{width:1,height:24,background:"#E5E7EB"}}/>

        {/* Undo/Redo */}
        <Btn onClick={()=>{
          if(!history.length) return;
          const prev=history[history.length-1];
          setFuture(f=>[pieces,...f]);
          setHistory(h=>h.slice(0,-1));
          setPieces(prev);
          SoundEngine.play('undo');
        }} disabled={!history.length} title="Undo (Ctrl+Z)">↩ Undo</Btn>
        <Btn onClick={()=>{
          if(!future.length) return;
          const next=future[0];
          setHistory(h=>[...h,pieces].slice(-MAX_UNDO));
          setFuture(f=>f.slice(1));
          setPieces(next);
          SoundEngine.play('pickup');
        }} disabled={!future.length} title="Redo (Ctrl+Y)">↪ Redo</Btn>

        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
          {entry?.solution && <ProgressBar snappedCount={snappedCount} total={totalPieces}/>}
          <Pill>🕐 {fmtTime}</Pill>
          <Pill>👣 {moves}</Pill>
          <Btn onClick={()=>setSoundOn(v=>!v)} title="Toggle sound">
            {soundOn?"🔊":"🔇"}
          </Btn>
          <Btn onClick={doSave}>💾 Save</Btn>
          <Btn onClick={doLoad}>📂 Load</Btn>
          <Btn onClick={exportPNG}>🖼 Export</Btn>
          <Btn danger onClick={()=>onQuit?onQuit():alert("Hook up onQuit")}>✕ Quit</Btn>
        </div>
      </div>

      {/* ── TRACE BAR ── */}
      <div style={{
        display:"flex", alignItems:"center", gap:10, flexWrap:"wrap",
        padding:"7px 16px", paddingLeft:LEFT_GUTTER+12,
        borderBottom:"1px dashed #E5E7EB", background:"#FEFEFE", fontSize:12, color:"#6B7280"
      }}>
        <label style={{display:"flex",alignItems:"center",gap:4}}>
          <input type="checkbox" checked={traceOn} onChange={e=>setTraceOn(e.target.checked)}/> Trace Mode
        </label>
        <input type="file" accept="image/*" onChange={onTraceFile} style={{fontSize:12}}/>
        {traceOn && <>
          <SliderLabel label="X" min={0} max={boardW} value={trace.x} onChange={v=>setTrace(t=>({...t,x:v}))}/>
          <SliderLabel label="Y" min={0} max={boardH} value={trace.y} onChange={v=>setTrace(t=>({...t,y:v}))}/>
          <SliderLabel label="Scale" min={0.2} max={2} step={0.01} value={trace.scale} onChange={v=>setTrace(t=>({...t,scale:v}))}/>
          <SliderLabel label="Rotate" min={-180} max={180} step={1} value={deg(trace.angle)} onChange={v=>setTrace(t=>({...t,angle:rad(v)}))}/>
          <SliderLabel label="Opacity" min={0} max={1} step={0.01} value={trace.opacity} onChange={v=>setTrace(t=>({...t,opacity:v}))}/>
        </>}
        <Btn onClick={saveImageAsPuzzle}>📷 Save as Puzzle</Btn>
        <Btn onClick={useCurrentLayoutAsSolution}>📌 Use Layout as Solution</Btn>
        <Btn onClick={deleteCurrentCustom}>🗑 Delete Custom</Btn>
      </div>

      {/* ── BOARD SIZE BAR ── */}
      <div style={{
        display:"flex", alignItems:"center", gap:8,
        padding:"5px 16px", paddingLeft:LEFT_GUTTER+12,
        borderBottom:"1px dashed #E5E7EB", background:"#FEFEFE", fontSize:12
      }}>
        <label style={labelStyle}>Board
          <select onChange={e=>{ const v=e.target.value; if(v==="wide"){setBoardW(1600);setBoardH(1100);} if(v==="xl"){setBoardW(2200);setBoardH(1400);} }}
            style={{marginLeft:4,borderRadius:6,border:"1px solid #D1D5DB",padding:"2px 6px",fontSize:12}}>
            <option value="wide">Wide</option>
            <option value="xl">XL</option>
          </select>
        </label>
        <label style={labelStyle}>W <input type="number" min="600" step="50" value={boardW} onChange={e=>setBoardW(Math.max(600,+e.target.value))} style={{width:80,marginLeft:4}}/></label>
        <label style={labelStyle}>H <input type="number" min="400" step="50" value={boardH} onChange={e=>setBoardH(Math.max(400,+e.target.value))} style={{width:80,marginLeft:4}}/></label>
        <span style={{marginLeft:8,color:"#9CA3AF"}}>Snap grid: {snap.grid}px · angle: {snap.angle}°</span>
        <label style={{...labelStyle,marginLeft:8}}>Grid <input type="number" min="0" step="1" value={snap.grid} onChange={e=>setSnap(s=>({...s,grid:+e.target.value}))} style={{width:56,marginLeft:4}}/></label>
        <label style={labelStyle}>Angle <input type="number" min="0" step="1" value={snap.angle} onChange={e=>setSnap(s=>({...s,angle:+e.target.value}))} style={{width:56,marginLeft:4}}/></label>
      </div>

      {/* ── IMPORTER ── */}
      <BookImporter
        onCreateMany={(entries)=>{
          const names=new Set(customList.map(x=>x.name));
          const list=customList.slice();
          entries.forEach(e=>{
            let base=e.name, k=1;
            while(names.has(e.name)){e.name=`${base} (${++k})`;}
            names.add(e.name); list.push(e);
          });
          setCustomList(list); saveCustomList(list);
          setPuzzleName(entries[0]?.name||puzzleName); setShowHint(true);
          flash(`Added ${entries.length} form(s) ✓`,"success");
        }}
      />

      {/* ── BOARD ── */}
      <div style={{
        flex:1, overflow:"auto", padding:"12px", paddingLeft:LEFT_GUTTER+12,
        position:"relative", background:"#F8FAFC"
      }}>
        <svg
          ref={svgRef}
          width={boardW} height={boardH}
          viewBox={`0 0 ${boardW} ${boardH}`}
          style={{
            background:"#fff",
            border:"1px solid #E5E7EB",
            borderRadius:16,
            boxShadow:"0 4px 24px rgba(0,0,0,0.08)",
            userSelect:"none", WebkitUserDrag:"none", touchAction:"none",
            display:"block"
          }}
          onDoubleClick={(e)=>{
            const r=svgRef.current.getBoundingClientRect();
            const id=hitAt(piecesRef.current,e.clientX-r.left,e.clientY-r.top);
            if(!id) return;
            pushHistory([...pieces]);
            setSelected(id);
            setPieces(arr=>arr.map(p=>p.id===id?{...p,angle:snapAngle(p.angle+rad(45),snap.angle)}:p));
            SoundEngine.play('rotate');
          }}
        >
          {/* Background */}
          <defs>
            <pattern id="grid" width="15" height="15" patternUnits="userSpaceOnUse">
              <path d="M 15 0 L 0 0 0 15" fill="none" stroke="#F3F4F6" strokeWidth="0.5"/>
            </pattern>
            {/* Glow filter for snapped pieces */}
            <filter id="snapGlow">
              <feGaussianBlur stdDeviation="4" result="blur"/>
              <feComposite in="SourceGraphic" in2="blur" operator="over"/>
            </filter>
            <filter id="selectedGlow">
              <feGaussianBlur stdDeviation="3" result="blur"/>
              <feComposite in="SourceGraphic" in2="blur" operator="over"/>
            </filter>
          </defs>
          <rect width={boardW} height={boardH} fill="url(#grid)"/>
          <rect x={MARGIN} y={MARGIN} width={boardW-2*MARGIN} height={boardH-2*MARGIN}
            fill="none" stroke="#E5E7EB" strokeWidth="1.5" rx="8"/>

          {/* Photo hint */}
          {(() => {
            const ce = entry;
            if (showHint && ce?.hintImage) {
              const h = ce.hintImage;
              return <image href={h.dataUrl} opacity={0.2}
                transform={`translate(${h.x} ${h.y}) rotate(${deg(h.angle||0)}) scale(${h.scale||1}) translate(${-boardW/2} ${-boardH/2})`}
                style={{pointerEvents:"none"}} width={boardW} height={boardH}/>;
            }
            if (traceOn && trace.url) {
              return <image href={trace.url} opacity={trace.opacity}
                transform={`translate(${trace.x} ${trace.y}) rotate(${deg(trace.angle)}) scale(${trace.scale}) translate(${-boardW/2} ${-boardH/2})`}
                style={{pointerEvents:"none"}} width={boardW} height={boardH}/>;
            }
            return null;
          })()}

          {/* Polygon hint (solution outline) */}
          {showHint && entry?.solution && Object.keys(entry.solution).map(id=>{
            const base=pieces.find(p=>p.id===id)||pieces[0];
            const t=entry.solution[id];
            const verts=transformVerts(base.verts,{x:t.x,y:t.y},t.angle||0,t.mirrorX||1);
            return <polygon key={`hint-${id}`} points={verts.map(([x,y])=>`${x},${y}`).join(" ")}
              fill="none" stroke="#CBD5E1" strokeWidth="1.5" strokeDasharray="4,3" opacity="0.7"/>;
          })}

          {/* Snap highlight ghost: show solution outline brighter when close */}
          {entry?.solution && Object.keys(entry.solution).map(id=>{
            if(!snappedPieces.has(id)) return null;
            const base=pieces.find(p=>p.id===id)||pieces[0];
            const t=entry.solution[id];
            const verts=transformVerts(base.verts,{x:t.x,y:t.y},t.angle||0,t.mirrorX||1);
            return <polygon key={`snap-${id}`} points={verts.map(([x,y])=>`${x},${y}`).join(" ")}
              fill="rgba(52,211,153,0.18)" stroke="#10B981" strokeWidth="2.5" opacity="1"/>;
          })}

          {/* Pieces */}
          {pieces.map(p => {
            const isSelected = p.id===selected;
            const isSnapped = snappedPieces.has(p.id);
            const transform = `translate(${p.x} ${p.y}) rotate(${deg(p.angle)}) scale(${p.mirrorX} 1)`;
            const [cx,cy] = centroid(p.verts);
            return (
              <g key={p.id} transform={transform}
                style={{cursor:isSelected?"grabbing":"grab"}}
                onPointerDown={e=>dragHandlers.current&&dragHandlers.current(p.id,e)}>

                {/* Shadow / glow behind piece */}
                {isSnapped && <polygon points={pts(p.verts)} fill="rgba(52,211,153,0.3)"
                  filter="url(#snapGlow)" style={{pointerEvents:"none"}}/>}
                {isSelected && <polygon points={pts(p.verts)} fill="rgba(99,102,241,0.25)"
                  filter="url(#selectedGlow)" style={{pointerEvents:"none"}}/>}

                <polygon
                  points={pts(p.verts)}
                  fill={p.color}
                  stroke={isSnapped ? "#10B981" : isSelected ? "#4F46E5" : "rgba(255,255,255,0.4)"}
                  strokeWidth={isSelected||isSnapped ? 2.5 : 1.5}
                  style={{
                    filter: isSelected ? "brightness(1.1)" : "none",
                    transition:"stroke 0.2s, filter 0.2s"
                  }}
                />
                {/* Subtle inner highlight */}
                <polygon points={pts(p.verts)} fill="none"
                  stroke="rgba(255,255,255,0.35)" strokeWidth="1"
                  style={{pointerEvents:"none"}}/>

                <circle cx={cx} cy={cy} r={3} fill="rgba(0,0,0,0.25)" style={{pointerEvents:"none"}}/>
                <text x={cx} y={cy+4} fontSize="11" fill="rgba(255,255,255,0.9)"
                  textAnchor="middle" style={{pointerEvents:"none",fontWeight:700,userSelect:"none"}}>
                  {p.id}
                </text>
                {isSelected && (
                  <text x={cx} y={cy+18} fontSize="10" fill="rgba(255,255,255,0.85)"
                    textAnchor="middle" style={{pointerEvents:"none",userSelect:"none"}}>
                    {Math.round(((deg(p.angle) % 360) + 360) % 360)}°
                  </text>
                )}
              </g>
            );
          })}
        </svg>

        {/* Toast */}
        {msg && (
          <div style={{
            position:"absolute", top:20, right:20,
            background: msgType==="success" ? "#059669" : msgType==="error" ? "#DC2626" : "rgba(17,24,39,0.9)",
            color:"#fff", padding:"10px 16px", borderRadius:12, fontSize:14,
            fontWeight:600, boxShadow:"0 4px 20px rgba(0,0,0,0.2)",
            pointerEvents:"none", zIndex:100,
            animation:"fadeIn 0.2s ease"
          }}>{msg}</div>
        )}

        <div style={{marginTop:8, fontSize:11, color:"#9CA3AF"}}>
          Drag to move · Scroll wheel = 45° · Shift+Scroll = 15° · R / Shift+R = rotate · F = flip ▱ · Double-click = +45° · Ctrl+Z undo
        </div>
      </div>

      <RulesModal open={rulesOpen} onClose={()=>setRulesOpen(false)}/>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&display=swap');
        @keyframes fadeIn { from { opacity:0; transform:translateY(-4px); } to { opacity:1; transform:none; } }
        select, input[type=number] { outline:none; }
        select:focus, input:focus { border-color:#6366F1 !important; box-shadow:0 0 0 2px rgba(99,102,241,0.15); }
      `}</style>
    </div>
  );
}

/* ========================= Shared UI primitives ========================= */
const btnBaseStyle = {
  background:"#F9FAFB", border:"1px solid #E5E7EB",
  padding:"5px 10px", borderRadius:8, cursor:"pointer",
  fontWeight:600, fontSize:13, color:"#374151",
  whiteSpace:"nowrap", display:"inline-flex", alignItems:"center", gap:4,
  transition:"background 0.15s, box-shadow 0.15s"
};

function Btn({ children, onClick, primary, danger, active, disabled, title }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={title}
      style={{
        ...btnBaseStyle,
        background: primary ? "#4F46E5" : danger ? "#FEF2F2" : active ? "#EEF2FF" : "#F9FAFB",
        color: primary ? "#fff" : danger ? "#DC2626" : active ? "#4F46E5" : "#374151",
        borderColor: primary ? "#4338CA" : danger ? "#FECACA" : active ? "#C7D2FE" : "#E5E7EB",
        opacity: disabled ? 0.45 : 1,
        cursor: disabled ? "not-allowed" : "pointer"
      }}
    >{children}</button>
  );
}

function Pill({ children }) {
  return (
    <span style={{
      background:"#F3F4F6", border:"1px solid #E5E7EB",
      padding:"4px 10px", borderRadius:999, fontSize:12, color:"#6B7280",
      whiteSpace:"nowrap"
    }}>{children}</span>
  );
}

function SliderLabel({ label, min, max, step=1, value, onChange }) {
  return (
    <label style={{display:"flex",alignItems:"center",gap:4,fontSize:12,color:"#6B7280"}}>
      {label}
      <input type="range" min={min} max={max} step={step} value={value}
        onChange={e=>onChange(+e.target.value)}
        style={{width:80,accentColor:"#6366F1"}}/>
    </label>
  );
}
